    const testData = [1, 2, 3, 4, 5];
    const expectedData = [2, 4];
    const testFunction = (data: number) => data % 2 === 0;
    let index = 0;

    const read = () => {
      return (end: any, cb: any) => {
        if (index >= testData.length) {
          cb(true, null);
        } else {
          cb(false, testData[index++]);
